        if i + BLOCK_SIZE <= n * k:
            tl.store(out_batch + i, tl.load(B_batch + i, mask=tl.arange(0, BLOCK_SIZE) < n * k - i))

    # Solve triangular system
    for j in range(k):
        for i in range(n):
            if upper:
                # Upper triangular solve
                if i < n - 1:
                    # Compute sum of products
                    sum_val = tl.zeros((1,), dtype=tl.float32)
