    n_B, k_B = B.shape[-2], B.shape[-1]
    n_L, n_L2 = L.shape[-2], L.shape[-1]

    if n_B != n_L or n_L != n_L2:
        raise ValueError("Matrix dimensions must be consistent")

    # Determine dtype
    dtype = B.dtype
    if dtype not in [torch.float32, torch.float64, torch.complex64, torch.complex128]:
        raise ValueError("Unsupported dtype")

    # Handle out tensor
    if out is None:
        out = torch.empty_like(B)
    else:
        if out.shape != B.shape:
            raise ValueError("out tensor must have the same shape as B")

    # Prepare batch dimensions
    batch_size = 1
    for dim in batch_dims_B:
        batch_size *= dim

    # Launch kernel
