@triton.jit
def _solve_kernel(
    A_ptr, B_ptr, out_ptr,
    n, batch_size,
    BLOCK_SIZE: tl.constexpr,
    IS_DOUBLE: tl.constexpr
):
    batch_idx = tl.program_id(0)
    if batch_idx >= batch_size:
        return

    A_batch = A_ptr + batch_idx * n * n
    B_batch = B_ptr + batch_idx * n
    out_batch = out_ptr + batch_idx * n

    # Allocate shared memory for the matrix and vector
    A_shared = tl.shared_memory(dtype=tl.float64 if IS_DOUBLE else tl.float32, shape=(BLOCK_SIZE, BLOCK_SIZE))
    B_shared = tl.shared_memory(dtype=tl.float64 if IS_DOUBLE else tl.float32, shape=(BLOCK_SIZE,))

    # Load matrix A and vector B into shared memory
    for i in range(0, n, BLOCK_SIZE):
        for j in range(0, n, BLOCK_SIZE):
            if i + tl.program_id(1) < n and j + tl.program_id(2) < n:
                A_shared[tl.program_id(1) + tl.program_id(2) * BLOCK_SIZE] = A_batch[i + tl.program_id(1) + (j + tl.program_id(2)) * n]

    for i in range(0, n, BLOCK_SIZE):
        if i + tl.program_id(1) < n:
            B_shared[tl.program_id(1)] = B_batch[i + tl.program_id(1)]

    # Perform Gaussian elimination with partial pivoting
    for k in range(n):
        # Find pivot
        pivot_row = k
        pivot_val = A_shared[k + k * BLOCK_SIZE]
        for i in range(k + 1, n):
            if abs(A_shared[i + k * BLOCK_SIZE]) > abs(pivot_val):
                pivot_row = i
                pivot_val = A_shared[i + k * BLOCK_SIZE]

        # Swap rows if needed
        if pivot_row != k:
            for j in range(n):
                temp = A_shared[k + j * BLOCK_SIZE]
                A_shared[k + j * BLOCK_SIZE] = A_shared[pivot_row + j * BLOCK_SIZE]
                A_shared[pivot_row + j * BLOCK_SIZE] = temp

        # Eliminate
        for i in range(k + 1, n):
            factor = A_shared[i + k * BLOCK_SIZE] / A_shared[k + k * BLOCK_SIZE]
            for j in range(k, n):
                A_shared[i + j * BLOCK_SIZE] -= factor * A_shared[k + j * BLOCK_SIZE]
            B_shared[i] -= factor * B_shared[k]

    # Back substitution
    for i in range(n - 1, -1, -1):
        for j in range(i + 1, n):
            B_shared[i] -= A_shared[i + j * BLOCK_SIZE] * B_shared[j]
        B_shared[i] /= A_shared[i + i * BLOCK_SIZE]

    # Store result
    for i in range(0, n, BLOCK_SIZE):
        if i + tl.program_id(1) < n:
            out_batch[i + tl.program_id(1)] = B_shared[tl.program_id(1)]

